import { useState } from 'react';

function Admin() {
  const [products, setProducts] = useState([
    { id: 1, name: '상품 1', price: 10000, category: '식품' },
    { id: 2, name: '상품 2', price: 20000, category: '생활용품' },
  ]);

  const [form, setForm] = useState({
    name: '',
    price: '',
    category: '',
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = () => {
    if (!form.name || !form.price || !form.category) {
      alert('모든 항목을 입력해주세요!');
      return;
    }
    const newProduct = {
      id: products.length + 1,
      name: form.name,
      price: Number(form.price),
      category: form.category,
    };
    setProducts([...products, newProduct]);
    setForm({ name: '', price: '', category: '' });
  };

  const handleDelete = (id) => {
    setProducts(products.filter((p) => p.id !== id));
  };

  return (
    <div style={{ padding: '24px', maxWidth: '800px', margin: '0 auto' }}>
      <h2 style={{ marginBottom: '24px' }}>🛠️ 관리자 페이지 - 상품 등록</h2>

      {/* 상품 등록 폼 */}
      <div style={{ background: '#f5f5f5', padding: '20px', borderRadius: '8px', marginBottom: '32px' }}>
        <h3 style={{ marginBottom: '16px' }}>상품 등록</h3>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
          <input
            name="name"
            value={form.name}
            onChange={handleChange}
            placeholder="상품명"
            style={{ padding: '10px', borderRadius: '4px', border: '1px solid #ddd', fontSize: '14px' }}
          />
          <input
            name="price"
            value={form.price}
            onChange={handleChange}
            placeholder="가격 (숫자만)"
            type="number"
            style={{ padding: '10px', borderRadius: '4px', border: '1px solid #ddd', fontSize: '14px' }}
          />
          <select
            name="category"
            value={form.category}
            onChange={handleChange}
            style={{ padding: '10px', borderRadius: '4px', border: '1px solid #ddd', fontSize: '14px' }}
          >
            <option value="">카테고리 선택</option>
            <option value="식품">식품</option>
            <option value="생활용품">생활용품</option>
            <option value="음료">음료</option>
            <option value="냉동식품">냉동식품</option>
            <option value="과자/간식">과자/간식</option>
          </select>
          <button
            onClick={handleSubmit}
            style={{ padding: '12px', background: '#1a73e8', color: 'white', border: 'none', borderRadius: '4px', fontSize: '15px', cursor: 'pointer' }}
          >
            상품 등록
          </button>
        </div>
      </div>

      {/* 상품 목록 */}
      <h3 style={{ marginBottom: '16px' }}>등록된 상품 목록</h3>
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr style={{ background: '#1a73e8', color: 'white' }}>
            <th style={{ padding: '12px', textAlign: 'left' }}>번호</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>상품명</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>가격</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>카테고리</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>관리</th>
          </tr>
        </thead>
        <tbody>
          {products.map((product) => (
            <tr key={product.id} style={{ borderBottom: '1px solid #ddd' }}>
              <td style={{ padding: '12px' }}>{product.id}</td>
              <td style={{ padding: '12px' }}>{product.name}</td>
              <td style={{ padding: '12px' }}>₩{product.price.toLocaleString()}</td>
              <td style={{ padding: '12px' }}>{product.category}</td>
              <td style={{ padding: '12px' }}>
                <button
                  onClick={() => handleDelete(product.id)}
                  style={{ padding: '6px 12px', background: '#e53935', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}
                >
                  삭제
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default Admin;
